definition.script:
pipeline {
  agent any
  stages {
    stage('Deploy API') {
      steps {
        build job: 'PIC-SURE Wildfly Stack Deploy', parameters: [
          [$class: 'StringParameterValue', name: 'S3_BUCKET_NAME', value: params.S3_BUCKET_NAME],
          [$class: 'StringParameterValue', name: 'TARGET_STACK', value: params.TARGET_STACK],
          [$class: 'BooleanParameterValue', name: 'DEPLOY_API', value: true],
          [$class: 'BooleanParameterValue', name: 'DEPLOY_PSAMA', value: false],
          [$class: 'BooleanParameterValue', name: 'DEPLOY_DICTIONARY', value: false]
        ]
      }
    }
  }
}
